module RefModule(CLK, LOAD, DATA_IN, DATA_OUT);
input CLK;
input LOAD;
input [7:0] DATA_IN;
output reg [7:0] DATA_OUT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (LOAD) begin
        DATA_OUT <= DATA_IN;
    end else begin
        DATA_OUT <= DATA_OUT >> 1;
    end
end

endmodule
